Replace it with:

```typescript
    // Sanitize tool schemas and strip unsupported params for kimi/deepseek
    pi.on("before_provider_request", (event: any, ctx: any) => {
      const model = ctx?.model;
      if (!model || model.provider !== "nyro") return;
      const id = model.id?.toLowerCase() ?? "";
      const payload = event?.payload;
      if (!payload || typeof payload !== "object") return;

      // Kimi: strip temperature/top_p (fixed per Kimi API docs)
      if (id.includes("kimi")) {
        delete payload.temperature;
        delete payload.top_p;
      }

      // Kimi + DeepSeek: sanitize tool schemas (Moonshot rejects non-standard JSON Schema)
      if ((id.includes("kimi") || id.includes("deepseek")) && payload.tools && Array.isArray(payload.tools)) {
        for (const tool of payload.tools) {
          if (tool?.function?.parameters) {
            sanitizeSchema(tool.function.parameters);
          }
        }
      }
    });
```

