```typescript
// Recursively sanitize JSON Schema for Moonshot/Kimi compatibility.
// Moonshot rejects: anyOf with parent type, if/then/else, description after $ref.
function sanitizeSchema(schema: any): void {
  if (!schema || typeof schema !== "object") return;

  // Move parent type into each anyOf/oneOf branch
  if (schema.type && (schema.anyOf || schema.oneOf)) {
    const key = schema.anyOf ? "anyOf" : "oneOf";
    const parentType = schema.type;
    delete schema.type;
    for (const branch of schema[key]) {
      if (!branch.type) branch.type = parentType;
      sanitizeSchema(branch);
    }
  }

  // Remove if/then/else (Moonshot doesn't support conditional schemas)
  delete schema.if;
  delete schema.then;
  delete schema.else;

  // Recurse
  if (schema.properties) {
    for (const prop of Object.values(schema.properties)) {
      sanitizeSchema(prop as any);
    }
  }
  if (schema.items) sanitizeSchema(schema.items);
  if (schema.anyOf) schema.anyOf.forEach(sanitizeSchema);
  if (schema.oneOf) schema.oneOf.forEach(sanitizeSchema);
  if (schema.allOf) schema.allOf.forEach(sanitizeSchema);
}
```

Place `sanitizeSchema` before the `export default` function. Apply these changes.
